export const CATEGORY_MAP = categoryMap;

// Import products from new-products.json (–Я—А–∞–є—Б 1.xlsx)
import newProductsData from './new-products.json' with { type: "json" };
import price1ProductsData from './price1-products.json' with { type: "json" };
import price2ProductsData from './price2-products.json' with { type: "json" };
import price3ProductsData from './price3-products.json' with { type: "json" };
import imageMapData from './image-map.json' with { type: "json" };

const RAW_PRODUCTS = [...newProductsData, ...price1ProductsData, ...price2ProductsData, ...price3ProductsData];

const BLANK_PHOTO = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="300"><rect fill="%23f1f5f9" width="400" height="300"/><text x="200" y="150" text-anchor="middle" dominant-baseline="middle" fill="%2364748b" font-family="system-ui,sans-serif" font-size="16">–§–Њ—В–Њ —Б–Ї–Њ—А–Њ –±—Г–і–µ—В</text></svg>';

function getProductImage(code, article) {
  if (!code && !article) return BLANK_PHOTO;
  
  // Try code first
  if (code) {
    const codeStr = String(code);
    const images = imageMapData[codeStr] || imageMapData[codeStr.padStart(5, '0')];
    if (images && images.length > 0) {
      return `/${images[0]}`;
    }
  }
  
  // Try article (lowercase)
  if (article) {
    const articleStr = String(article).toLowerCase();
    const images = imageMapData[articleStr];
    if (images && images.length > 0) {
      return `/${images[0]}`;
    }
  }
  
  return BLANK_PHOTO;
}

export const PRODUCTS = RAW_PRODUCTS.map((p, index) => {
  // Resolve mapping: try exact match, normalized match, and substring matches
  function normalizeKey(s) {
    return String(s || '').toLowerCase().replace(/[^a-z0-9–∞-—П—С]+/g, ' ').trim();
  }

  const normalizedCategoryMap = Object.fromEntries(
    Object.entries(categoryMap).map(([k, v]) => [normalizeKey(k), v])
  );

  const rawKey = p.category_raw || p.category || '';
  let mapping = categoryMap[rawKey];

  // Heuristic: map products by keywords in name/fullName/category_raw
  if (!mapping) {
    const txt = (String(p.name || '') + ' ' + String(p.fullName || '') + ' ' + String(p.category_raw || '')).toLowerCase();
    // match camera-specific words only (avoid matching "–≤–Є–і–µ–Њ–Ї–∞—А—В—Л")
    const hasVideo = /–≤–Є–і–µ–Њ–Ї–∞–Љ|–≤–Є–і–µ–Њ–Ї–∞–Љ–µ—А–∞|–≤–Є–і–µ–Њ—А–µ–≥–Є—Б—В—А–∞—В|–≤–Є–і–µ–Њ–і–Њ–Љ–Њ—Д–Њ–љ|–≤–Є–і–µ–Њ–і–Њ–Љ–Њ—Д/i.test(txt);
    const hasAnalog = /–∞–љ–∞–ї–Њ–≥|cvbs|hdcvi|tvi|ahd|cvbs/i.test(txt);
    const hasIp = /ip\b|ip\s|ip-/i.test(txt);
    const hasHybrid = /–≥–Є–±—А–Є–і|hybrid/i.test(txt);

    if (hasVideo) {
      if (hasAnalog || hasHybrid) {
        mapping = { category: 'videonablyudenie', subcategory: 'analogovye-videokamery' };
      } else if (hasIp) {
        mapping = { category: 'videonablyudenie', subcategory: 'ip-videokamery' };
      } else {
        // default to IP video if unclear
        mapping = { category: 'videonablyudenie', subcategory: 'ip-videokamery' };
      }
    }

    // If product is a recorder mention, map to registrators
    if (!mapping && /–≤–Є–і–µ–Њ—А–µ–≥–Є—Б—В—А–∞—В|—А–µ–≥–Є—Б—В—А–∞—В–Њ—А/i.test(txt)) {
      if (hasHybrid || hasAnalog) mapping = { category: 'videonablyudenie', subcategory: 'gibridnye-videoregistratory' };
      else mapping = { category: 'videonablyudenie', subcategory: 'ip-videoregistratory' };
    }
  }
  if (!mapping) mapping = normalizedCategoryMap[normalizeKey(rawKey)];
  if (!mapping) {
    // try substring matches (product key contains map key)
    const rawLower = String(rawKey).toLowerCase();
    for (const k of Object.keys(categoryMap)) {
      if (!k) continue;
      if (rawLower.includes(k.toLowerCase())) {
        mapping = categoryMap[k];
        break;
      }
    }
  }
  if (!mapping) {
    // reverse: map key contains product key
    const rawLower = String(rawKey).toLowerCase();
    for (const k of Object.keys(categoryMap)) {
      if (!k) continue;
      if (k.toLowerCase().includes(rawLower) && rawLower.length > 2) {
        mapping = categoryMap[k];
        break;
      }
    }
  }

  const cat = mapping ? mapping.category : p.category;
  const subcat = mapping ? mapping.subcategory : p.subcategory;
  
  return {
    ...p,
    id: `prod-${p.code || index}-${index}`,
    title: p.name || p.fullName || '–С–µ–Ј –љ–∞–Ј–≤–∞–љ–Є—П',
    articul: p.article || String(p.code),
    sku: p.article || String(p.code),
    brand: "",
    brand_name: "",
    price: Number(p.price) || 0,
    stock: 10,
    is_available: true,
    category: cat || 'other',
    category_raw: p.category_raw,
    image: getProductImage(p.code, p.article),
    description: p.fullName || p.name || "",
    subcategory: subcat || 'other'
  };
});

